describe("clamp", () => {
  it("returns the minimum when value is below range", () => {
    expect(clamp(1, 3, 8)).toBe(3);
  });

  it("returns the maximum when value is above range", () => {
    expect(clamp(10, 3, 8)).toBe(8);
  });

  it("returns the original value when it is inside range", () => {
    expect(clamp(5, 3, 8)).toBe(5);
  });
});
```

